import { ServiceDetailClient } from "@/components/ServiceDetailClient";
import { CATEGORIES } from "@/app/(main)/products/data";
import { seo } from "@/lib/seo/metadata";
import { JsonLd } from "@/components/JsonLd";
import { Metadata } from "next";
import Link from "next/link";

type Props = {
  params: Promise<{ categorySlug: string; serviceSlug: string }>;
};

async function getServiceDetail(categorySlug: string, serviceSlug: string) {
  try {
    const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/categories/${categorySlug}`);
    if (!res.ok) return null;
    const category = await res.json();
    const service = category.capabilities?.find((s: any) => s.slug === serviceSlug);
    return { category, service };
  } catch (error) {
    console.error('Fetch error:', error);
    return null;
  }
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { categorySlug, serviceSlug } = await params;
  const data = await getServiceDetail(categorySlug, serviceSlug);

  if (!data?.service) return {};

  return seo({
    title: `${data.service.name} | Agara Sofvix`,
    description: data.service.description,
    path: `/services/${categorySlug}/${serviceSlug}`,
    keywords: [data.service.name, data.category.name, "Enterprise Software", "Custom Solutions"]
  });
}

export default async function ServiceDetailPage({ params }: Props) {
  const { categorySlug, serviceSlug } = await params;
  const data = await getServiceDetail(categorySlug, serviceSlug);

  if (!data || !data.category || !data.service) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-white p-6 text-center">
        <h1 className="text-4xl font-bold mb-4">Service Not Found</h1>
        <p className="text-gray-600 mb-8">The requested service could not be located in our system.</p>
        <Link href="/products" className="text-[#F97316] font-bold hover:underline">Return to Products</Link>
      </div>
    );
  }

  const { category, service } = data;

  const serviceSchema = {
    name: service.name,
    description: service.description,
    provider: {
      "@type": "LocalBusiness",
      "name": "Agara Sofvix"
    },
    areaServed: "Global",
    hasOfferCatalog: {
      "@type": "OfferCatalog",
      "name": service.name,
      "itemListElement": service.features?.map((f: string) => ({
        "@type": "Offer",
        "itemOffered": {
          "@type": "Service",
          "name": f
        }
      })) || []
    }
  };

  return (
    <>
      <JsonLd type="Service" data={serviceSchema} />
      <ServiceDetailClient 
        category={category} 
        service={service} 
        categorySlug={categorySlug} 
        serviceSlug={serviceSlug} 
      />
    </>
  );
}
